import{_ as n,c as i,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Plattformen und Integrationen: Multi-Modell-KI-Konfiguration | oh-my-opencode","description":"Lerne, wie du mehrere KI-Plattformen (Anthropic, OpenAI, Google, Copilot) konfigurierst und verwaltest, und beherrsche automatische Fallback-Mechanismen und intelligente Modellauswahl.","frontmatter":{"title":"Plattformen und Integrationen: Multi-Modell-KI-Konfiguration | oh-my-opencode","sidebarTitle":"Verbinde deine KI-Konten","subtitle":"Plattformen und Integrationen: Multi-Modell-KI-Konfiguration","description":"Lerne, wie du mehrere KI-Plattformen (Anthropic, OpenAI, Google, Copilot) konfigurierst und verwaltest, und beherrsche automatische Fallback-Mechanismen und intelligente Modellauswahl.","order":40},"headers":[],"relativePath":"de/code-yeongyu/oh-my-opencode/platforms/index.md","filePath":"de/code-yeongyu/oh-my-opencode/platforms/index.md"}'),a={name:"de/code-yeongyu/oh-my-opencode/platforms/index.md"};function s(l,e,o,d,u,h){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="plattformen-und-integrationen" tabindex="-1">Plattformen und Integrationen <a class="header-anchor" href="#plattformen-und-integrationen" aria-label="Permalink to &quot;Plattformen und Integrationen&quot;">​</a></h1><p>Dieses Kapitel erklärt, wie du mehrere KI-Provider (Anthropic, OpenAI, Google, GitHub Copilot usw.) konfigurierst und verwaltest, sowie den automatischen Multi-Modell-Fallback-Mechanismus von oh-my-opencode.</p><p>Durch das Studium dieses Kapitels wirst du beherrschen, wie das System basierend auf dem Aufgabentyp und den verfügbaren Modellen intelligent das am besten geeignete KI-Modell auswählt, um effiziente und zuverlässige Multi-Modell-Orchestrierungs-Workflows zu erstellen.</p><h2 id="was-dieses-kapitel-abdeckt" tabindex="-1">Was dieses Kapitel abdeckt <a class="header-anchor" href="#was-dieses-kapitel-abdeckt" aria-label="Permalink to &quot;Was dieses Kapitel abdeckt&quot;">​</a></h2><p>Dieses Kapitel ist in zwei Teile unterteilt:</p><h3 id="_1-provider-konfiguration" tabindex="-1">1. <a href="./provider-setup/">Provider-Konfiguration</a> <a class="header-anchor" href="#_1-provider-konfiguration" aria-label="Permalink to &quot;1. [Provider-Konfiguration](provider-setup/)&quot;">​</a></h3><p>Lerne, wie du verschiedene KI-Provider konfigurierst, einschließlich:</p><ul><li>Anthropic Claude (erste Wahl des Haupt-Orchestrators)</li><li>OpenAI ChatGPT (spezialisiert auf Architektur-Reviews)</li><li>Google Gemini (Frontend- und Medienanalyse)</li><li>GitHub Copilot (Backup-Provider)</li><li>Z.ai Coding Plan und OpenCode Zen (optionale Dienste)</li></ul><p><strong>Was du lernen wirst</strong>:</p><ul><li>✅ 6 mainstream KI-Provider konfigurieren</li><li>✅ Den interaktiven Installer für schnelles Setup verwenden</li><li>✅ Die am besten geeigneten Modelle für verschiedene Agents angeben</li><li>✅ Den <code>doctor</code>-Befehl verwenden, um Konfigurationsprobleme zu diagnostizieren</li></ul><p><strong>Geschätzte Zeit</strong>: 25-30 Minuten</p><h3 id="_2-multi-modell-strategie" tabindex="-1">2. <a href="./model-resolution/">Multi-Modell-Strategie</a> <a class="header-anchor" href="#_2-multi-modell-strategie" aria-label="Permalink to &quot;2. [Multi-Modell-Strategie](model-resolution/)&quot;">​</a></h3><p>Vertiefe dich in den dreistufigen Prioritätsmechanismus des Modellauswahl-Systems:</p><ul><li>Benutzerüberschreibung (präzise Kontrolle)</li><li>Provider-Fallback (automatische Fehlertoleranz)</li><li>Systemstandard (Fallback-Lösung)</li></ul><p><strong>Was du lernen wirst</strong>:</p><ul><li>✅ Den kompletten Workflow der Modellauswahl verstehen</li><li>✅ Basierend auf Aufgabenanforderungen manuell Modelle angeben</li><li>✅ Provider-Fallback nutzen, um die Systemrobustheit zu verbessern</li><li>✅ Modellauswahl-Probleme diagnostizieren und lösen</li></ul><p><strong>Geschätzte Zeit</strong>: 30-35 Minuten</p><h2 id="empfohlener-lernpfad" tabindex="-1">Empfohlener Lernpfad <a class="header-anchor" href="#empfohlener-lernpfad" aria-label="Permalink to &quot;Empfohlener Lernpfad&quot;">​</a></h2><p>Wir empfehlen, dieses Kapitel in der folgenden Reihenfolge zu studieren:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Installation abgeschlossen] --&gt; B[Provider-Konfiguration]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Multi-Modell-Strategie]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Erweiterte Funktionen]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bfdbfe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#93c5fd</span></span></code></pre></div><p><strong>Warum diese Reihenfolge?</strong></p><ol><li><strong>Zuerst konfigurieren, dann verstehen</strong>: Lerne zuerst, wie du jeden Provider konfigurierst, und verstehe dann den dahinterliegenden Auflösungsmechanismus</li><li><strong>Von einfach zu komplex</strong>: Die Provider-Konfiguration ist eine grundlegende Operation, die Multi-Modell-Strategie ist ein fortgeschrittenes Konzept</li><li><strong>Praxis validiert Theorie</strong>: Nach der Konfiguration der Provider kannst du den <code>doctor</code>-Befehl verwenden, um die Wirksamkeit der Multi-Modell-Strategie zu verifizieren</li></ol><div class="tip custom-block"><p class="custom-block-title">Schnellstart-Pfad</p><p>Wenn du nur schnell loslegen möchtest, kannst du die Schritte 1-4 der <a href="./provider-setup/">Provider-Konfiguration</a> abschließen (konfiguriere grundlegende Provider) und den Rest später bei Bedarf lernen.</p></div><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor du dieses Kapitel studierst, stelle sicher, dass:</p><ul><li>✅ <a href="./../installation/">Installation und Erstkonfiguration</a> abgeschlossen ist</li><li>✅ OpenCode installiert ist (Version &gt;= 1.0.150)</li><li>✅ Du grundlegende JSON/JSONC-Konfigurationsdateiformate verstehst</li><li>✅ Du mindestens ein KI-Provider-Abonnement hast (Anthropic Claude empfohlen)</li></ul><div class="warning custom-block"><p class="custom-block-title">Was, wenn ich kein Provider-Konto habe?</p><p>Du kannst die Konfigurationsschritte zuerst lernen, ohne tatsächlich einen Provider zu verbinden. Das System verwendet das Standardmodell von OpenCode als Fallback.</p></div><h2 id="haufig-gestellte-fragen" tabindex="-1">Häufig gestellte Fragen <a class="header-anchor" href="#haufig-gestellte-fragen" aria-label="Permalink to &quot;Häufig gestellte Fragen&quot;">​</a></h2><details><summary><strong>Muss ich alle Provider konfigurieren?</strong></summary><p>Nein. Du kannst nur die Provider konfigurieren, die du am häufigsten verwendest (zum Beispiel nur Anthropic Claude). Der Provider-Fallback-Mechanismus von oh-my-opencode verwendet automatisch verfügbare Provider.</p><p>Wenn du jedoch die Vorteile der Multi-Modell-Orchestrierung voll ausschöpfen möchtest, empfehlen wir, mindestens 2-3 Provider zu konfigurieren, damit das System basierend auf dem Aufgabentyp automatisch das am besten geeignete Modell auswählen kann.</p></details><details><summary><strong>Was ist der Unterschied zwischen Provider-Konfiguration und Modellauswahl?</strong></summary><ul><li><strong>Provider-Konfiguration</strong>: Der &quot;Installationsschritt&quot;, der dem System mitteilt, welche KI-Dienste verfügbar sind</li><li><strong>Modellauswahl</strong>: Die &quot;Entscheidungslogik&quot;, wie das System auswählt, welcher Provider für jeden Agent verwendet werden soll</li></ul><p>Analogie: Die Provider-Konfiguration ist &quot;Teammitglieder einstellen&quot;, die Modellauswahl ist &quot;Aufgaben zuweisen&quot;.</p></details><details><summary><strong>Kann ich die Konfiguration jederzeit ändern?</strong></summary><p>Du kannst die Konfigurationsdatei jederzeit ändern:</p><ul><li>Benutzerkonfiguration: <code>~/.config/opencode/oh-my-opencode.json</code></li><li>Projektkonfiguration: <code>.opencode/oh-my-opencode.json</code></li></ul><p>Änderungen werden beim nächsten Verwenden eines Agents automatisch wirksam. Wenn du die Provider-Authentifizierung geändert hast, musst du <code>opencode auth login</code> ausführen, um sich erneut zu authentifizieren.</p></details> ## Nächste Schritte <p>Nach Abschluss dieses Kapitels kannst du:</p><h3 id="empfohlener-pfad-ki-agent-team-lernen" tabindex="-1">Empfohlener Pfad: KI-Agent-Team lernen <a class="header-anchor" href="#empfohlener-pfad-ki-agent-team-lernen" aria-label="Permalink to &quot;Empfohlener Pfad: KI-Agent-Team lernen&quot;">​</a></h3><p>Fahre fort mit <a href="./../../advanced/ai-agents-overview/">KI-Agent-Team: 10 Experten-Übersicht</a>, um zu verstehen, wie du verschiedene Agents für spezialisierte Aufgaben verwendest.</p><h3 id="fortgeschrittener-pfad-tiefgreifende-anpassung" tabindex="-1">Fortgeschrittener Pfad: Tiefgreifende Anpassung <a class="header-anchor" href="#fortgeschrittener-pfad-tiefgreifende-anpassung" aria-label="Permalink to &quot;Fortgeschrittener Pfad: Tiefgreifende Anpassung&quot;">​</a></h3><p>Wenn du bereits mit der Grundkonfiguration vertraut bist, kannst du zu <a href="./../../advanced/advanced-configuration/">Konfigurationstiefe: Agent- und Berechtigungsverwaltung</a> springen, um zu lernen:</p><ul><li>Wie du Agent-Prompts anpasst</li><li>Wie du Agent-Berechtigungen und Zugriffsbereiche einstellst</li><li>Wie du benutzerdefinierte Agents und Kategorien erstellst</li></ul><h3 id="praktischer-pfad-prometheus-planung-verwenden" tabindex="-1">Praktischer Pfad: Prometheus-Planung verwenden <a class="header-anchor" href="#praktischer-pfad-prometheus-planung-verwenden" aria-label="Permalink to &quot;Praktischer Pfad: Prometheus-Planung verwenden&quot;">​</a></h3><p>Beginne mit der Verwendung von <a href="./../../advanced/prometheus-planning/">Prometheus-Planung: Interview-basierte Anforderungsermittlung</a>, um die Leistungsfähigkeit der Multi-Modell-Orchestrierung durch tatsächliche Agent-Zusammenarbeit zu erleben.</p><hr><p><strong>Loslegen</strong>: Beginne deine Multi-Modell-Orchestrierungs-Reise mit der <a href="./provider-setup/">Provider-Konfiguration</a>!</p>`,42)])])}const c=n(a,[["render",s]]);export{p as __pageData,c as default};
